var speed = 0;
var activeInterval = null;
var idleInterval = null;

var speedVal = document.getElementById('speed-val');
var speedBar = document.getElementById('speed-bar');
var btnUp = document.getElementById('btn-up');
var btnDown = document.getElementById('btn-down');

function updateDisplay() {
  speedVal.textContent = String(speed).padStart(3, '0');
  var ratio = speed / 150;
  var r = Math.floor(ratio * 2 * 255);
  var g = Math.floor((1 - ratio) * 255 + 100);
  if (r > 255) r = 255;
  if (g > 255) g = 255;
  var color = 'rgb(' + r + ',' + g + ',80)';
  speedVal.style.color = color;
  speedVal.style.textShadow = '0 0 18px ' + color;
  speedBar.style.width = (ratio * 100) + '%';
}

function clearActive() {
  if (activeInterval) { clearInterval(activeInterval); activeInterval = null; }
}

function startIdle() {
  if (idleInterval) return;
  idleInterval = setInterval(function() {
    if (speed > 0) { speed--; updateDisplay(); }
  }, 500);
}

function stopIdle() {
  if (idleInterval) { clearInterval(idleInterval); idleInterval = null; }
}

function pressUp() {
  stopIdle();
  clearActive();
  btnUp.classList.add('pedal-pressed');
  activeInterval = setInterval(function() {
    if (speed < 150) { speed++; updateDisplay(); }
  }, 200);
}

function releaseUp() {
  if (!btnUp.classList.contains('pedal-pressed')) return;
  clearActive();
  btnUp.classList.remove('pedal-pressed');
  startIdle();
}

function pressDown() {
  stopIdle();
  clearActive();
  btnDown.classList.add('pedal-pressed');
  activeInterval = setInterval(function() {
    if (speed > 0) { speed--; updateDisplay(); }
  }, 100);
}

function releaseDown() {
  if (!btnDown.classList.contains('pedal-pressed')) return;
  clearActive();
  btnDown.classList.remove('pedal-pressed');
  startIdle();
}

btnUp.addEventListener('mousedown', pressUp);
btnUp.addEventListener('mouseup', releaseUp);
btnUp.addEventListener('mouseleave', releaseUp);
btnDown.addEventListener('mousedown', pressDown);
btnDown.addEventListener('mouseup', releaseDown);
btnDown.addEventListener('mouseleave', releaseDown);

btnUp.addEventListener('touchstart', function(e) { e.preventDefault(); pressUp(); });
btnUp.addEventListener('touchend', releaseUp);
btnDown.addEventListener('touchstart', function(e) { e.preventDefault(); pressDown(); });
btnDown.addEventListener('touchend', releaseDown);

startIdle();
updateDisplay();

