// Bad approach — attaching a listener to every single item
// const items = document.querySelectorAll('.item');
// items.forEach(item => item.addEventListener('click', handler)); // slow for large lists
// Also won't work for items added dynamically after this code runs!

// Good approach — one listener on the parent
const list = document.querySelector('#myList');

list.addEventListener('click', function(event) {
  // event.target is the actual element the user clicked
  if (event.target.classList.contains('item')) {
    console.log('Clicked item:', event.target.textContent);
    event.target.classList.toggle('selected');
  }
});

// Now this works even for items added later!
const newItem = document.createElement('li');
newItem.className = 'item';
newItem.textContent = 'I was added dynamically';
list.appendChild(newItem); // the click handler already works on this

function handleClick(event) {
  console.log('Clicked!', event.target);
}

const button = document.querySelector('#myButton');

// Add the listener
button.addEventListener('click', handleClick);

// Remove it — must pass the exact same function reference
button.removeEventListener('click', handleClick); // works

// This will NOT work — it's a different function instance
// button.removeEventListener('click', () => console.log('hi')); // fails silently

// --- Modern approach: AbortController ---
const controller = new AbortController();

button.addEventListener('click', handleClick, {
  signal: controller.signal
});

document.addEventListener('keydown', handleClick, {
  signal: controller.signal
});

// Remove ALL listeners attached to this controller at once
controller.abort();

