var dragged = null;
var items = document.querySelectorAll('.drag-item');
var log = document.getElementById('event-log');

function setLog(msg) {
  log.textContent = msg;
}

items.forEach(function(item) {
  item.addEventListener('dragstart', function() {
    dragged = item;
    setTimeout(function() { item.classList.add('dragging'); }, 0);
    setLog('dragstart: "' + item.textContent.trim() + '"');
  });

  item.addEventListener('dragend', function() {
    item.classList.remove('dragging');
    setLog('drop complete!');
    setTimeout(function() { log.textContent = ''; }, 1500);
  });

  item.addEventListener('dragover', function(e) {
    e.preventDefault();
    if (item !== dragged) item.classList.add('drag-over');
    setLog('dragover: "' + item.textContent.trim() + '"');
  });

  item.addEventListener('dragleave', function() {
    item.classList.remove('drag-over');
  });

  item.addEventListener('drop', function(e) {
    e.preventDefault();
    item.classList.remove('drag-over');
    if (item !== dragged) {
      var list = document.getElementById('drag-list');
      var all = Array.prototype.slice.call(list.children);
      var di = all.indexOf(dragged);
      var ti = all.indexOf(item);
      if (di < ti) {
        list.insertBefore(dragged, item.nextSibling);
      } else {
        list.insertBefore(dragged, item);
      }
      setLog('drop: order updated!');
    }
  });
});

